import dspy
from dspy.utils.dummies import DummyLM


class RewriteInstruction(dspy.Signature):
    current_instruction: str = dspy.InputField()
    feedback_blob: str = dspy.InputField()
    improved_instruction: str = dspy.OutputField()


class ExternalReflectionProposer:
    def __init__(self):
        self.rewriter = dspy.Predict(RewriteInstruction)
        # Dict-mode DummyLM keyed on the always-present output field name
        # 'improved_instruction', so it NEVER exhausts no matter how many times
        # GEPA's reflection loop invokes the proposer (a fixed-length list-mode
        # DummyLM would, once drained, emit an unparseable response).
        self.external_lm = DummyLM(
            {'improved_instruction': {'improved_instruction': 'Answer with the exact short answer and no extra text.'}}
        )

    def __call__(self, candidate, reflective_dataset, components_to_update):
        updated = {}
        with dspy.context(lm=self.external_lm):
            for name in components_to_update:
                feedback_blob = '\n'.join(ex['Feedback'] for ex in reflective_dataset.get(name, [])) or 'No feedback yet.'
                updated[name] = self.rewriter(
                    current_instruction=candidate[name],
                    feedback_blob=feedback_blob,
                ).improved_instruction
        return updated


class QAProgram(dspy.Module):
    def __init__(self):
        super().__init__()
        self.predictor = dspy.Predict('question -> answer')

    def forward(self, question):
        return self.predictor(question=question)


def metric(gold, pred, trace=None, pred_name=None, pred_trace=None):
    score = float(pred.answer.strip().lower() == gold.answer.lower())
    return dspy.Prediction(score=score, feedback='Return the exact short answer and nothing else.')


proposer = ExternalReflectionProposer()
task_lm = DummyLM({'capital of France': {'answer': 'Lyon'}})
dspy.configure(lm=task_lm)
trainset = [
    dspy.Example(question='What is the capital of France?', answer='Paris').with_inputs('question'),
]

optimized = dspy.GEPA(
    metric=metric,
    reflection_lm=None,
    instruction_proposer=proposer,
    max_metric_calls=5,
    seed=0,
).compile(QAProgram(), trainset=trainset, valset=trainset)

print({
    'optimized_instruction': optimized.predictor.signature.instructions,
    'external_reflection_calls': len(proposer.external_lm.history),
})
