class QuestAgent(dspy.Module):
    def __init__(self, env: TinyWorld):
        super().__init__()
        self.agent = dspy.ReAct('goal -> outcome', tools=[env.ask, env.move, env.take], max_iters=3)

    def forward(self, goal: str) -> dspy.Prediction:
        return self.agent(goal=goal)


