from types import SimpleNamespace

import dspy


class ExistingVectorClient:
    def __init__(self, namespaces: dict[str, list[str]]):
        self.namespaces = namespaces

    def search(self, query: str, limit: int, namespace: str) -> list[str]:
        docs = self.namespaces[namespace]
        scored = sorted(
            docs,
            key=lambda doc: sum(token.lower() in doc.lower() for token in query.split()),
            reverse=True,
        )
        return scored[:limit]


class ExistingRM:
    def __init__(self, client: ExistingVectorClient):
        self.client = client

    def __call__(self, query: str, k: int = 3, **kwargs):
        namespace = kwargs.get('namespace', 'support')
        docs = self.client.search(query, limit=k, namespace=namespace)
        return [SimpleNamespace(long_text=text) for text in docs]


class AnswerFromContext(dspy.Signature):
    context = dspy.InputField()
    question = dspy.InputField()
    answer = dspy.OutputField()


class ExistingRAG(dspy.Module):
    def __init__(self):
        super().__init__()
        self.retrieve = dspy.Retrieve(k=3)
        self.answer = dspy.ChainOfThought(AnswerFromContext)

    def forward(self, question: str, namespace: str = 'support'):
        context = self.retrieve(question, namespace=namespace).passages
        pred = self.answer(context=context, question=question)
        return dspy.Prediction(context=context, answer=pred.answer)


client = ExistingVectorClient(
    {
        'support': [
            'TLS certificate renewals are tracked in the ops checklist.',
            'Refund exceptions are approved by finance directors.',
            'API tokens are rotated from the admin console.',
        ]
    }
)

dspy.configure(lm=dspy.LM('openai/gpt-4o-mini'), rm=ExistingRM(client))
program = ExistingRAG()
result = program(question='Where do we track TLS certificate renewals?')
