from typing import Literal

import dspy
import pydantic
from dspy.utils import DummyLM


class LabelDecision(pydantic.BaseModel):
    label: str
    created_new: bool


class BaseTicketLabeler(dspy.Signature):
    'Choose an existing label or request a new one.'

    text: str = dspy.InputField()
    known_labels: list[str] = dspy.InputField(desc='Previously accepted labels.')
    choice: str = dspy.OutputField(desc='Pick one existing label or __NEW__.')
    new_label: str | None = dspy.OutputField(desc='Use None unless choice is __NEW__.')


class TicketLabeler(dspy.Module):
    def forward(self, text: str, known_labels: list[str]) -> LabelDecision:
        dynamic_sig = BaseTicketLabeler.with_updated_fields(
            'choice',
            type_=Literal[tuple([*known_labels, '__NEW__'])],
        )
        pred = dspy.Predict(dynamic_sig)(text=text, known_labels=known_labels)

        if pred.choice == '__NEW__':
            if pred.new_label is None:
                raise ValueError('LM chose __NEW__ without providing new_label')
            return LabelDecision(label=pred.new_label, created_new=True)

        return LabelDecision(label=pred.choice, created_new=False)


dspy.configure(
    lm=DummyLM(
        [
            {
                'choice': '__NEW__',
                'new_label': 'billing_issue',
            }
        ]
    )
)

result = TicketLabeler()(
    text='My invoice shows duplicate charges for the same seat.',
    known_labels=['bug_report', 'feature_request', 'access_problem'],
)

assert result == LabelDecision(label='billing_issue', created_new=True)
