import dspy
from dspy.evaluate import Evaluate
from dspy.utils.dummies import DummyLM


class ShortAnswerer(dspy.Module):
    def __init__(self):
        super().__init__()
        self.qa = dspy.Predict('question -> answer')

    def forward(self, question):
        return self.qa(question=question)


def exact_and_brief(example, pred, trace=None):
    exact = float(example.answer == pred.answer)
    brief = float(len(pred.answer.split()) <= 3)
    return dspy.Prediction(
        score=0.7 * exact + 0.3 * brief,
        exact=exact,
        brief=brief,
        feedback=f'exact={exact}, brief={brief}',
    )


trainset = [
    dspy.Example(question='2+2?', answer='4').with_inputs('question'),
    dspy.Example(question='Capital of France?', answer='Paris').with_inputs('question'),
]
devset = [
    dspy.Example(question='3+3?', answer='6').with_inputs('question'),
    dspy.Example(question='Largest ocean?', answer='Pacific').with_inputs('question'),
]


dspy.configure(
    lm=DummyLM(
        {
            '2+2?': {'answer': '4'},
            'Capital of France?': {'answer': 'Paris'},
            '3+3?': {'answer': '6'},
            'Largest ocean?': {'answer': 'Pacific Ocean'},
        }
    )
)

optimizer = dspy.BootstrapFewShot(
    metric=exact_and_brief,
    metric_threshold=0.75,
    max_bootstrapped_demos=1,
    max_labeled_demos=2,
)
compiled = optimizer.compile(
    student=ShortAnswerer(),
    teacher=ShortAnswerer(),
    trainset=trainset,
)

result = Evaluate(
    devset=devset,
    metric=exact_and_brief,
    num_threads=1,
    display_progress=False,
)(compiled)

breakdown = [
    {'question': example.question, **metric_output.toDict()}
    for example, _, metric_output in result.results
]

print({'overall_percent': result.score, 'per_example': breakdown})
