import dspy
from dspy.evaluate import Evaluate, answer_exact_match, answer_passage_match
from dspy.utils.dummies import DummyLM


class AnswerFromContext(dspy.Signature):
    question: str = dspy.InputField()
    context: list[str] = dspy.InputField()
    answer: str = dspy.OutputField()


class TinyRAG(dspy.Module):
    def __init__(self):
        super().__init__()
        self.answer = dspy.Predict(AnswerFromContext)
        self.corpus = {
            'Where is the Eiffel Tower?': ['Paris | The Eiffel Tower is in Paris, France.'],
            'What is the largest ocean?': ['Pacific | The Pacific Ocean is the largest ocean on Earth.'],
        }

    def forward(self, question):
        context = self.corpus[question]
        pred = self.answer(question=question, context=context)
        return dspy.Prediction(answer=pred.answer, context=context)


def answer_and_support(example, pred, trace=None):
    exact = answer_exact_match(example, pred)
    supported = answer_passage_match(example, pred)
    return float(exact and supported)


devset = [
    dspy.Example(question='Where is the Eiffel Tower?', answer='Paris').with_inputs('question'),
    dspy.Example(question='What is the largest ocean?', answer='Pacific Ocean').with_inputs('question'),
]


dspy.configure(
    lm=DummyLM(
        {
            'Where is the Eiffel Tower?': {'answer': 'Paris'},
            'What is the largest ocean?': {'answer': 'Pacific Ocean'},
        }
    )
)

result = Evaluate(
    devset=devset,
    metric=answer_and_support,
    num_threads=1,
    display_progress=False,
)(TinyRAG())

per_example = [
    {'question': example.question, 'score': score}
    for example, _, score in result.results
]

print({'overall_percent': result.score, 'per_example': per_example})
